import { describe, expect, it } from '@a0n/gnosis/test';

import {
  compileVrmAvatarRuntimeManifest,
  evaluateAvatarPose,
  mixAvatarMorphDeltas,
  solveLookAtBoneDeltas,
  type GnosisAvatarCompilationInput,
} from './avatar';

function buildCompilationInput(): GnosisAvatarCompilationInput {
  return {
    nodeNames: [
      'Root',
      'Hips',
      'Spine',
      'Chest',
      'Neck',
      'Head',
      'LeftEye',
      'RightEye',
      'FaceMesh',
    ],
    morphSources: [
      {
        nodeIndex: 8,
        meshName: 'FaceMesh',
        targetNames: ['Blink', 'Happy', 'AA'],
      },
    ],
    vrm: {
      meta: {
        name: 'Twin Witness',
        version: '1.0.0',
        authors: ['Forkjoin'],
      },
      humanoid: {
        humanBones: {
          hips: { node: 1 },
          spine: { node: 2 },
          chest: { node: 3 },
          neck: { node: 4 },
          head: { node: 5 },
          leftEye: { node: 6 },
          rightEye: { node: 7 },
        },
      },
      expressions: {
        preset: {
          happy: {
            morphTargetBinds: [{ node: 8, index: 1, weight: 100 }],
          },
          blink: {
            morphTargetBinds: [{ node: 8, index: 0, weight: 100 }],
            isBinary: true,
          },
        },
      },
    },
  };
}

describe('compileVrmAvatarRuntimeManifest', () => {
  it('maps humanoid bones and VRM expressions into compact slots', () => {
    const manifest = compileVrmAvatarRuntimeManifest(buildCompilationInput());

    expect(manifest.bones.map((bone) => bone.semantic)).toContain('head');
    expect(manifest.expressions.find((entry) => entry.name === 'happy')).toEqual(
      {
        name: 'happy',
        binary: false,
        morphBinds: [{ slot: 1, weight: 1 }],
      }
    );
    expect(manifest.visemeAliases.aa).toEqual([2]);
  });
});

describe('solveLookAtBoneDeltas', () => {
  it('solves clamped head and eye rotations deterministically', () => {
    const manifest = compileVrmAvatarRuntimeManifest(buildCompilationInput());
    const deltas = solveLookAtBoneDeltas(manifest, { x: 2, y: 1, z: 1 });

    expect(deltas.map((delta) => delta.slot)).toEqual([4, 5, 6]);
    expect(deltas[0]?.rotation.y).not.toBe(0);
  });
});

describe('mixAvatarMorphDeltas', () => {
  it('mixes explicit expressions, blink, and visemes into stable weights', () => {
    const manifest = compileVrmAvatarRuntimeManifest(buildCompilationInput());
    const deltas = mixAvatarMorphDeltas(manifest, {
      timestampMs: 100,
      blink: 1,
      expressionWeights: { happy: 0.65 },
      visemes: { aa: 0.4 },
    });

    expect(deltas).toEqual([
      { slot: 0, weight: 1 },
      { slot: 1, weight: 0.65 },
      { slot: 2, weight: 0.4 },
    ]);
  });
});

describe('evaluateAvatarPose', () => {
  it('returns deterministic pose output for the same signal frame', () => {
    const manifest = compileVrmAvatarRuntimeManifest(buildCompilationInput());
    const frame = {
      timestampMs: 2_000,
      speechState: 'speaking' as const,
      gazeTarget: { x: 0.4, y: 0.2, z: 1 },
      visemes: { aa: 0.8 },
      emotion: {
        dominantEmotion: 'happy',
        arousal: 0.7,
        stress: 0.15,
        focus: 0.8,
      },
    };

    expect(evaluateAvatarPose(manifest, frame)).toEqual(
      evaluateAvatarPose(manifest, frame)
    );
  });
});
